mapper.select:
SELECT r.id AS id, r.title AS title, r.start_date AS start_date, r.end_date AS end_date, r.status AS status, r.streak_seq AS streak_seq, (SELECT string_agg(c.status, ',' ORDER BY c.day_index) FROM resolution_checks c WHERE c.resolution_id = r.id) AS day_statuses FROM resolutions r WHERE r.user_id = #{userId} AND r.deleted_at IS NULL
AND r.status = #{status}
AND r.id < #{cursor}
ORDER BY r.id DESC LIMIT #{limit}

SELECT EXISTS(
    SELECT 1
      FROM resolutions
     WHERE streak_group_id = #{streakGroupId}::uuid
       AND streak_seq = #{streakSeq}
)

mapper.update:
UPDATE resolutions
   SET deleted_at = now()
 WHERE id = #{id}
   AND user_id = #{userId}
   AND deleted_at IS NULL
